import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.ByXR59UU.js";const u=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/getting-started/overview.md","filePath":"openshield-xdp/getting-started/overview.md","lastUpdated":null}'),i={name:"openshield-xdp/getting-started/overview.md"};function r(n,e,d,l,h,c){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p>OpenShield-XDP is an XDP-native DDoS mitigation engine that inspects and drops attack traffic inside the NIC driver — before the kernel allocates an skb, before iptables runs.</p><h2 id="why-xdp" tabindex="-1">Why XDP? <a class="header-anchor" href="#why-xdp" aria-label="Permalink to &quot;Why XDP?&quot;">​</a></h2><p>XDP operates at the earliest point in the Linux stack: directly on DMA packet buffers, with zero per-packet allocation, zero sk_buff overhead, and zero context switches. A single core processes 10M+ PPS.</p><h2 id="when-to-use" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to use&quot;">​</a></h2><p>Game servers under UDP reflection floods. Web servers under SYN floods. DNS resolvers under amplification attacks. Any public-facing service at risk of L3/L4 DDoS.</p><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p>42 detection vectors across L2–L7. Suspicion scoring, SYNPROXY cookies, rate limiting, subnet bans. 7-screen TUI dashboard. Webhook alerts (Discord/Slack).</p><h2 id="what-it-doesn-t-do" tabindex="-1">What it doesn&#39;t do <a class="header-anchor" href="#what-it-doesn-t-do" aria-label="Permalink to &quot;What it doesn&#39;t do&quot;">​</a></h2><p>Doesn&#39;t replace iptables (different layer). Doesn&#39;t intercept TLS (L2–L4 only). Isn&#39;t a WAF.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/getting-started/installation">Installation</a> · <a href="/pingless-studios-docs/openshield-xdp/getting-started/quick-start">Quick Start</a></p>',12)])])}const f=t(i,[["render",r]]);export{u as __pageData,f as default};
